#include<bits/stdc++.h>
using namespace std;
int k,n;
map<int,int> mp;
int b[100010];
void dfs(int x)
{
    int sum=0;
    if(x>k)
    {
        for(int i=x-1;i>=x-k;i--)
        {
            sum=sum*2+b[i];
        }
        if(mp[sum]!=0)
        {
            return;
        }
        mp[sum]=1;
    }
    if(x==n+1)
    {
        for(int i=x-1;i>=x-k;i--)
        {
            sum=sum*2+b[i];
        }
        if(mp[sum]!=0)
        {
            return;
        }
        b[n]=1;
        for(int i=1;i<=n;i++)
        {
            printf("%d",b[i]);
        }
        exit(0);
    }
    b[x]=0;
    dfs(x+1);
    b[x]=1;
    dfs(x+1);
    b[x]=0;
    if(x>k)
    {
        mp[sum]--;
    }
}
int main()
{
    scanf("%d",&k);
    n=(1<<k);
    printf("%d ",n);
    dfs(1);
    return 0;
}
